function decode(bytes) {
  let payload = bytes;
  let returnValue = {
    showers: {},
    state: {
      live: {},
    }

  };

  if ((payload[0] == 25) || (payload[0] == 27)) {
    //histo
    //Id(2)	Liters(2)	Flowrate(1)	Temperature(1)	Soaping time(1)	Number of soaping(1)	duration(2)
    let showerId = payload[1] + (payload[2] << 8);
    if (!returnValue.showers[showerId]) {
      returnValue.showers[showerId] = {}
    }
    returnValue.showers[showerId].liter = payload[3] + (payload[4] << 8);
    returnValue.showers[showerId].flow = payload[5];
    returnValue.showers[showerId].temperature = payload[6] << 4;
    returnValue.showers[showerId].soaping_time = payload[7];
    returnValue.showers[showerId].number_of_soaping = payload[8];
    returnValue.showers[showerId].duration = payload[9] + (payload[10] << 8);
  } else if (payload[0] == 26) {
    //live
    //Id(2)	Liters(2)	average Flowrate(2)	instant temperature(2)
    returnValue.state.live = {
      id: payload[1] + (payload[2] << 8),
      liter: payload[3] + (payload[4] << 8),
      averageFlow: payload[5] + (payload[6] << 8),
      instantTemperature: payload[7] + (payload[8] << 8),
      date: new Date().toISOString()
    };
    // returnValue.showers[returnValue.state.live.id] = {
    //     liter: returnValue.state.live.liter,
    //     date: returnValue.state.live.date,
    //     flow: returnValue.state.live.averageFlow
    // };

  } else if (payload[0] == 5) {
    //05 10 00 FF 00 20 00 00 FF 30 7D 00 7D 40 FF 00 00

    //threshold
    returnValue.state.thresholds = [];
    for (var i = 1; i < 17; i += 4) {
      returnValue.state.thresholds.push({
        liter: payload[i],
        color: 'FF' + (('0' + payload[i + 1].toString(16)).slice(-2) + ('0' + payload[i + 2].toString(16)).slice(-2) + ('0' + payload[i + 3].toString(16)).slice(-2)).toUpperCase()
      });
    }

  } else if (payload[0] == 7) {
    //calibration(2)
    returnValue.state.calibration = payload[1] + (payload[2] << 8);
  } else if (payload[0] == 12) {
    //get soaping threshold
    returnValue.state.soaping_threshold = payload[1] + (payload[2] << 8);
  }

  return {
    data: returnValue, // JSON object
    warnings: [], // Optional warnings
    errors: [] // Optional errors
  };
}

