const devEui = msg.payload.deviceInfo.devEui;
const deviceTags = msg.payload.deviceInfo.tags || {};
const receivedAt = msg.payload.time ?? new Date().toISOString();

const LIVE_KEY = 'sh_live_' + devEui;
const THRESHOLDS_KEY = 'sh_thresh_' + devEui;
const PROCESSED_KEY = 'sh_done_' + devEui;

function computeTemp(rawValue) {
    return Math.round(((3096.4 - rawValue) / 40.403) * 10) / 10;
}

function computeFlow(rawFlow) {
    return Math.round((1000 * 60 * 20) / (610 * rawFlow * 4) * 100) / 100;
}

const decoded = msg.decodedData;
const { showers, state } = decoded.data;

// --- Thresholds ---
let currentThresholds = flow.get(THRESHOLDS_KEY) || deviceTags.thresholds || null;
if (state.thresholds) {
    const thresholdsStr = JSON.stringify(state.thresholds);
    if (thresholdsStr !== currentThresholds) {
        flow.set(THRESHOLDS_KEY, thresholdsStr);
        msg.sh_data = { thresholds: thresholdsStr };
        currentThresholds = thresholdsStr;
    }
}

// --- Live shower ---
let liveShowers = flow.get(LIVE_KEY) || {};
let liveId;

if (state.live && state.live.id !== undefined) {
    const raw = state.live;
    liveId = raw.id;

    const liveFields = { volume: raw.liter };
    if (raw.averageFlow) liveFields.flow = computeFlow(raw.averageFlow);
    if (raw.instantTemperature) liveFields.temperature = computeTemp(raw.instantTemperature);

    liveShowers[liveId] = { date: receivedAt, volume: raw.liter };
    flow.set(LIVE_KEY, liveShowers);

    msg.live_data = [{
        measurement: "showers_live",
        tags: { devEui, showerId: String(liveId) },
        fields: liveFields,
        timestamp: new Date(receivedAt)
    }];
}

// --- Historical showers ---
const showerPoints = [];
const liveToDelete = [];
const processedShowers = flow.get(PROCESSED_KEY) || {};

for (const [showerId, showerData] of Object.entries(showers)) {
    const showerIdNum = parseInt(showerId, 10);
    if (liveId !== undefined && liveId === showerIdNum) continue;

    // Deduplication: skip showers already written to InfluxDB
    if (processedShowers[showerId]) continue;

    const dbLive = liveShowers[showerId] ?? null;
    let showerDate = showerData.date;
    if (dbLive) {
        showerDate = dbLive.date;
        delete liveShowers[showerId];
        liveToDelete.push({ devEui, showerId });
    } else if (!showerDate) {
        showerDate = receivedAt;
    }

    const fields = {
        volume: showerData.liter,
        duration: showerData.duration,
        soaping_time: showerData.soaping_time,
        number_of_soaping: showerData.number_of_soaping,
    };

    if (showerData.temperature) fields.temperature = computeTemp(showerData.temperature);
    if (showerData.flow && Number.isFinite(showerData.flow)) fields.flow = computeFlow(showerData.flow);

    const tags = { devEui, showerId };
    if (currentThresholds) tags.thresholds = currentThresholds;

    showerPoints.push({
        measurement: "showers",
        tags,
        fields,
        timestamp: new Date(showerDate)
    });

    processedShowers[showerId] = showerDate;
}

flow.set(LIVE_KEY, liveShowers);
flow.set(PROCESSED_KEY, processedShowers);

if (showerPoints.length > 0) {
    msg.shower_data = showerPoints;
}

if (liveToDelete.length > 0) {
    msg.delete_live_data = liveToDelete;
}

return msg;

