const CONTEXT_GATEWAYS=`gateways`;
const now = Date.now();
const OFFLINE_DELAY = 10 * 60 * 1000; // more than 10 mins without data => offline
const alertsData = [];

// prepare gateways status
let gateways = flow.get(CONTEXT_GATEWAYS);
if (!gateways) {
    gateways = {lastSeen: {}, offline: [], offlineId: {} };
}
//node.warn(gateways);

let gtwEUI;
if (msg.topic) {
    gtwEUI = msg.topic.split('/')[2];

    // --- manage current gateway => set online

    // store gateway last seen
    gateways.lastSeen[gtwEUI] = new Date().getTime();

    if (gateways.offline.indexOf(gtwEUI) > -1) {
        // CASE cancel offline alert

        gateways.offline = gateways.offline.filter((eui) => eui != gtwEUI);
        const alertId = gateways.offlineId[gtwEUI];
        delete gateways.offlineId[gtwEUI];

        // add in alert data for influxDB
        alertsData.push({
            measurement: "gateway_alerts",
            tags: { devEui: gtwEUI, alertId: alertId, alertType: "offline", severity: "critical" },
            fields: { value: 0 },
            timestamp: new Date()
        });
    }
}

// --- detect gateways offline
for (let eui of Object.keys(gateways.lastSeen)) {
    if (eui == gtwEUI) continue;

    let lastSeen = gateways.lastSeen[eui];
    if ((now - lastSeen) > OFFLINE_DELAY && gateways.offline.indexOf(eui) === -1) {
        // CASE trigger offline alert
        const alertId = "ID_" + Date.now();

        gateways.offline.push(eui);
        gateways.offlineId[eui] = alertId;

        // add in alert data for influxDB
        alertsData.push({
            measurement: "gateway_alerts",
            tags: { devEui: eui, alertId: alertId, alertType: "offline", severity: "critical" },
            fields: { value: 1 },
            timestamp: new Date()
        });
    }
}


flow.set(CONTEXT_GATEWAYS, gateways);

if (alertsData.length > 0) {
    msg.alert_data = alertsData;
    return msg;
}

return null;

