const endStr   = msg.endDate   || "2026-01-31";

const [sy, sm, sd] = startStr.split("-").map(Number);
const [ey, em, ed] = endStr.split("-").map(Number);
const startDate = new Date(sy, sm - 1, sd, 0, 0, 0);
const endDate   = new Date(ey, em - 1, ed, 23, 59, 59);

// --- Utilitaires ---
function rand(min, max)    { return min + Math.random() * (max - min); }
function randInt(min, max) { return Math.floor(rand(min, max + 1)); }
function clamp(v, min, max){ return Math.max(min, Math.min(max, v)); }
function round1(v)         { return Math.round(v * 10) / 10; }

function timestampAt(baseDate, hourFloat) {
    const ts = new Date(baseDate);
    ts.setHours(0, 0, 0, 0);
    return ts.getTime() + hourFloat * 3_600_000;
}

// --- Génère les champs d'une douche ---
function makeShower(ts, profile) {
    let duration, temperature, number_of_soaping, soaping_time, flow;

    if (profile === "hotel") {
        duration          = randInt(400, 900);
        temperature       = round1(rand(38, 44));
        number_of_soaping = randInt(1, 3);
        soaping_time      = number_of_soaping * randInt(20, 60);
        flow              = round1(rand(8, 13));
    } else if (profile === "camping") {
        duration          = randInt(180, 480);
        temperature       = round1(rand(34, 40));
        number_of_soaping = randInt(1, 2);
        soaping_time      = number_of_soaping * randInt(15, 35);
        flow              = round1(rand(6, 10));
    } else { // maison
        duration          = randInt(300, 800);
        temperature       = round1(rand(38, 43));
        number_of_soaping = randInt(2, 4);
        soaping_time      = number_of_soaping * randInt(20, 50);
        flow              = round1(rand(7, 11));
    }

    soaping_time = Math.min(soaping_time, duration - 60);
    const activeSeconds = Math.max(duration - soaping_time, 60);
    const volume = clamp(round1(activeSeconds / 60 * flow), 5, 200);

    return { volume, duration, soaping_time, number_of_soaping, temperature, flow, _ts: ts };
}

// --- Génère les douches jour par jour ---
const MONTH_FACTORS_CAMPING = [0.02, 0.02, 0.05, 0.20, 0.40, 0.70, 1.00, 1.00, 0.50, 0.15, 0.02, 0.02];

const showers = [];
let showerId = randInt(0, 100);

let cursor = new Date(startDate);
while (cursor <= endDate) {
    const dow      = cursor.getDay();   // 0=Dim, 6=Sam
    const month    = cursor.getMonth();
    const isWeekend = dow === 0 || dow === 6;
    const daySlots  = [];

    if (profile === "maison") {
        const residents = capacity || 2;
        for (let i = 0; i < residents; i++) {
            // Douche matin (fréquente)
            if (Math.random() < (isWeekend ? 0.80 : 0.65)) {
                const h = isWeekend ? rand(8, 11.5) : rand(6.5, 9.5);
                daySlots.push(makeShower(timestampAt(cursor, h), profile));
            }
            // Douche soir (moins fréquente)
            if (Math.random() < 0.25) {
                daySlots.push(makeShower(timestampAt(cursor, rand(19, 23)), profile));
            }
        }

    } else if (profile === "hotel") {
        const rooms       = capacity || 20;
        const occupancy   = isWeekend ? rand(0.75, 0.95) : rand(0.50, 0.75);
        const occupied    = Math.round(rooms * occupancy);
        for (let i = 0; i < occupied; i++) {
            // Douche matin (départ)
            if (Math.random() < 0.85) {
                daySlots.push(makeShower(timestampAt(cursor, rand(7, 11)), profile));
            }
            // Douche soir (arrivée / loisirs)
            if (Math.random() < 0.40) {
                daySlots.push(makeShower(timestampAt(cursor, rand(18, 23)), profile));
            }
        }

    } else if (profile === "camping") {
        const stalls      = capacity || 4;
        const seasonal    = MONTH_FACTORS_CAMPING[month];
        const usersPerStall = isWeekend ? rand(3, 6) : rand(1.5, 3.5);
        const total       = Math.round(stalls * usersPerStall * seasonal);
        for (let i = 0; i < total; i++) {
            const inMorning = Math.random() < 0.55;
            const h = inMorning ? rand(7.5, 10.5) : rand(17, 21);
            daySlots.push(makeShower(timestampAt(cursor, h), profile));
        }
    }

    // Tri chronologique + attribution des IDs
    daySlots.sort((a, b) => a._ts - b._ts);
    for (const s of daySlots) {
        const ts = s._ts;
        delete s._ts;
        showers.push({
            measurement: "showers",
            tags: { devEui, showerId: String(showerId) },
            fields: s,
            timestamp: new Date(ts)
        });
        showerId = (showerId + 1) % 65536;
    }

    cursor.setDate(cursor.getDate() + 1);
}

msg.shower_data = showers;
msg.debug = {
