        //     flow: returnValue.state.live.averageFlow / 4
        // };
    } else if (payload[0] == CMD_GET_LED_FULL_CONFIG_V3) {
        //05 10 00 FF 00 20 00 00 FF 30 7D 00 7D 40 FF 00 00

        //threshold
        returnValue.state.thresholds = [];
        for (var i = 1; i < 17; i += 4) {
            returnValue.state.thresholds.push({
